const mergedData = {};

for (const item of items) {
  Object.assign(mergedData, item.json);
}

return [{ json: mergedData }];

function normalizeText(s) {
  return String(s ?? "")
    .trim()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function onlyAZ09(s) {
  return String(s ?? "").replace(/[^a-z0-9]/g, "");
}

const fullRaw = $json.nombreCompleto ?? "";
const full = normalizeText(fullRaw);
const parts = full ? full.split(" ").filter(Boolean) : [];

let nombre1 = "";
let nombre2 = "";
let apellido1 = "";
let apellido2 = "";

if (parts.length >= 4) {
  nombre1 = parts[0];
  nombre2 = parts[1];
  apellido1 = parts[parts.length - 2];
  apellido2 = parts[parts.length - 1];
} 
else if (parts.length === 3) {
  nombre1 = parts[0];
  apellido1 = parts[1];
  apellido2 = parts[2];
} 
else if (parts.length === 2) {
  nombre1 = parts[0];
  apellido1 = parts[1];
} 
else if (parts.length === 1) {
  nombre1 = parts[0];
}

const nombreClean = onlyAZ09(nombre1);
const apellido1Clean = onlyAZ09(apellido1);
const apellido2Clean = onlyAZ09(apellido2);

const intento = 0;

let samCandidate = [nombreClean, apellido1Clean].filter(Boolean).join(".");
if (!samCandidate) samCandidate = "usuario";

const domain = "livecenter.com.co";
const upn = `${samCandidate}@${domain}`;

return {
  ...$json,
  nombre1,
  nombre2,
  apellido1,
  apellido2: apellido2Clean,
  intento,
  samBase: samCandidate,
  samCandidate,
  upn,
  email: upn
};

const original = $node["Generar username1"].json;

let actual = {};
try {
  actual = $node["Incrementar Intento1"].json;
} catch (e) {
  actual = original;
}

const usuarioNoExiste = $node["Consultar usuario AD"].json.error?.status === 500;

const resultadoFinal = {
  ...original,
  ...actual,
  samCandidate: actual.samCandidate || original.samCandidate,
  upn: actual.upn || original.upn
};

return [{ json: resultadoFinal }];

// 1. Buscamos el último intento exitoso que realizó este mismo nodo
let intentoActual = 0;
try {
    // Intentamos obtener el valor de la última vez que pasó por aquí
    intentoActual = $("Incrementar Intento1").last().json.intento || 0;
} catch (e) {
    intentoActual = 0;
}

const intento = intentoActual + 1;

// 2. Traemos los datos base del nodo donde se genera todo el flujo
// Cambia "Generar username1" por el nombre real de tu nodo inicial si es distinto
const origen = $("Generar username1").item.json;

const apellido2 = (origen.apellido2 || "").trim().toLowerCase();
const samBase = (origen.samBase || "").trim().toLowerCase();
const directorioId = (origen.ad ? origen.ad.directorioId : null) || origen.directorioId;

let extra = "";

// 3. Lógica de homónimos corregida
if (apellido2 && intento <= apellido2.length) {
    extra = apellido2.substring(0, intento);
} else {
    // Si ya probamos todas las letras, empezamos a poner números
    extra = apellido2 + (intento - apellido2.length);
}

const nuevoUsername = samBase + extra;

return [{
    json: {
        intento: intento,
        samBase: samBase,
        apellido2: apellido2,
        directorioId: directorioId,
        samCandidate: nuevoUsername,
        upn: nuevoUsername + "@livecenter.com.co",
        email: nuevoUsername + "@livecenter.com.co"
    }
}];

